// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/*
    OracleConsensus.sol

    PURPOSE
    -------
    Deterministic on-chain consensus engine for oracle submissions.
    This contract:
    - accepts signed oracle outcomes
    - aggregates weighted votes
    - finalizes consensus per market
    - exposes a single, canonical outcome to SettlementEngine

    GUARANTEES (from docs)
    ---------------------
    - No discretionary resolution
    - Deterministic aggregation
    - Weight bounded by stake & governance caps
    - Event-sourced, replayable decisions

    TRUST MODEL
    -----------
    - Individual oracles may be wrong
    - Economic majority assumed honest
    - Governance is fallback only
*/

import {OracleRegistry} from "./OracleRegistry.sol";
import {OracleStaking} from "./OracleStaking.sol";

contract OracleConsensus {
    /*//////////////////////////////////////////////////////////////
                                ERRORS
    //////////////////////////////////////////////////////////////*/

    error OnlyGovernance();
    error OracleNotActive();
    error AlreadySubmitted();
    error ConsensusClosed();
    error ConsensusNotFinalized();
    error InvalidMarket();
    error WeightCapExceeded();

    /*//////////////////////////////////////////////////////////////
                                EVENTS
    //////////////////////////////////////////////////////////////*/

    event OracleSubmitted(
        address indexed oracle,
        address indexed market,
        bool outcome,
        uint256 weight
    );

    event ConsensusFinalized(
        address indexed market,
        bool outcome,
        uint256 totalYesWeight,
        uint256 totalNoWeight
    );

    event WeightCapUpdated(uint256 newCap);

    /*//////////////////////////////////////////////////////////////
                              STORAGE
    //////////////////////////////////////////////////////////////*/

    address public governance;
    OracleRegistry public immutable oracleRegistry;
    OracleStaking public immutable oracleStaking;

    /// @notice Max weight an oracle can contribute (bps of total stake)
    uint256 public oracleWeightCapBps;

    struct MarketConsensus {
        bool finalized;
        bool outcome;
        uint256 yesWeight;
        uint256 noWeight;
        mapping(address => bool) submitted;
    }

    /// @notice market => consensus data
    mapping(address => MarketConsensus) private consensuses;

    /*//////////////////////////////////////////////////////////////
                              MODIFIERS
    //////////////////////////////////////////////////////////////*/

    modifier onlyGovernance() {
        if (msg.sender != governance) revert OnlyGovernance();
        _;
    }

    modifier onlyActiveOracle() {
        if (!oracleRegistry.isActiveOracle(msg.sender))
            revert OracleNotActive();
        _;
    }

    /*//////////////////////////////////////////////////////////////
                              CONSTRUCTOR
    //////////////////////////////////////////////////////////////*/

    constructor(
        address _governance,
        address _oracleRegistry,
        address _oracleStaking,
        uint256 _oracleWeightCapBps
    ) {
        require(_governance != address(0), "INVALID_GOVERNANCE");
        require(_oracleRegistry != address(0), "INVALID_REGISTRY");
        require(_oracleStaking != address(0), "INVALID_STAKING");

        governance = _governance;
        oracleRegistry = OracleRegistry(_oracleRegistry);
        oracleStaking = OracleStaking(_oracleStaking);
        oracleWeightCapBps = _oracleWeightCapBps;
    }

    /*//////////////////////////////////////////////////////////////
                        GOVERNANCE CONTROLS
    //////////////////////////////////////////////////////////////*/

    function updateWeightCap(uint256 newCapBps)
        external
        onlyGovernance
    {
        require(newCapBps <= 10_000, "INVALID_CAP");
        oracleWeightCapBps = newCapBps;
        emit WeightCapUpdated(newCapBps);
    }

    /*//////////////////////////////////////////////////////////////
                        SUBMISSION LOGIC
    //////////////////////////////////////////////////////////////*/

    /**
     * @notice Submit oracle outcome for a market
     */
    function submitOutcome(address market, bool outcome)
        external
        onlyActiveOracle
    {
        MarketConsensus storage mc = consensuses[market];

        if (mc.finalized) revert ConsensusClosed();
        if (mc.submitted[msg.sender]) revert AlreadySubmitted();

        uint256 oracleStake = oracleStaking.getStake(msg.sender);
        uint256 totalStake = oracleStaking.totalStaked();

        uint256 maxWeight =
            (totalStake * oracleWeightCapBps) / 10_000;

        uint256 weight =
            oracleStake > maxWeight ? maxWeight : oracleStake;

        if (weight == 0) revert WeightCapExceeded();

        mc.submitted[msg.sender] = true;

        if (outcome) {
            mc.yesWeight += weight;
        } else {
            mc.noWeight += weight;
        }

        emit OracleSubmitted(msg.sender, market, outcome, weight);
    }

    /*//////////////////////////////////////////////////////////////
                        FINALIZATION LOGIC
    //////////////////////////////////////////////////////////////*/

    /**
     * @notice Finalize consensus after submission window
     */
    function finalizeConsensus(address market)
        external
        onlyGovernance
    {
        MarketConsensus storage mc = consensuses[market];
        if (mc.finalized) revert ConsensusClosed();

        mc.finalized = true;
        mc.outcome = mc.yesWeight >= mc.noWeight;

        emit ConsensusFinalized(
            market,
            mc.outcome,
            mc.yesWeight,
            mc.noWeight
        );
    }

    /*//////////////////////////////////////////////////////////////
                        VIEW FUNCTIONS
    //////////////////////////////////////////////////////////////*/

    function isFinalized(address market) external view returns (bool) {
        return consensuses[market].finalized;
    }

    function getOutcome(address market)
        external
        view
        returns (bool outcome)
    {
        MarketConsensus storage mc = consensuses[market];
        if (!mc.finalized) revert ConsensusNotFinalized();
        return mc.outcome;
    }
}
","keccak256":"0xd9bff9d6d0cb68e5b25fd6aaf55aedc8f27a67718b119b7b263404f97ac9b30b","license":"MIT"},"oracles/OracleRegistry.sol":{"content":"// File: contracts/oracles/OracleRegistry.sol
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/*
    OracleRegistry.sol

    PURPOSE
    -------
    Canonical registry for decentralized oracle nodes.
    Enforces:
    - explicit oracle identity
    - stake-gated participation
    - metadata transparency
    - governance-bounded controls

    GUARANTEES (from docs)
    ---------------------
    - No anonymous oracle influence
    - No participation without stake
    - Deterministic, on-chain accountability
    - Non-custodial staking model

    TRUST MODEL
    -----------
    - Oracles are economically trusted, not inherently trusted
    - Governance is slow, bounded, auditable
*/

contract OracleRegistry {
    /*//////////////////////////////////////////////////////////////
                                ERRORS
    //////////////////////////////////////////////////////////////*/

    error OnlyGovernance();
    error OracleAlreadyRegistered();
    error OracleNotRegistered();
    error InvalidMetadata();

    /*//////////////////////////////////////////////////////////////
                                EVENTS
    //////////////////////////////////////////////////////////////*/

    event OracleRegistered(
        address indexed oracle,
        bytes32 indexed oracleId,
        string metadataURI
    );

    event OracleDeactivated(address indexed oracle);
    event OracleActivated(address indexed oracle);

    /*//////////////////////////////////////////////////////////////
                              STORAGE
    //////////////////////////////////////////////////////////////*/

    /// @notice Governance authority
    address public governance;

    struct Oracle {
        bytes32 oracleId;
        string metadataURI;
        bool active;
        bool exists;
    }

    /// @notice Oracle address => Oracle data
    mapping(address => Oracle) private oracles;

    /// @notice Total registered oracles
    uint256 public totalOracles;

    /*//////////////////////////////////////////////////////////////
                              MODIFIERS
    //////////////////////////////////////////////////////////////*/

    modifier onlyGovernance() {
        if (msg.sender != governance) revert OnlyGovernance();
        _;
    }

    /*//////////////////////////////////////////////////////////////
                              CONSTRUCTOR
    //////////////////////////////////////////////////////////////*/

    constructor(address _governance) {
        require(_governance != address(0), "INVALID_GOVERNANCE");
        governance = _governance;
    }

    /*//////////////////////////////////////////////////////////////
                        REGISTRATION LOGIC
    //////////////////////////////////////////////////////////////*/

    /**
     * @notice Register a new oracle
     * @param oracleId Deterministic identifier (model hash, operator id)
     * @param metadataURI IPFS/Arweave metadata reference
     */
    function registerOracle(bytes32 oracleId, string calldata metadataURI)
        external
    {
        if (oracles[msg.sender].exists) revert OracleAlreadyRegistered();
        if (bytes(metadataURI).length == 0) revert InvalidMetadata();

        oracles[msg.sender] = Oracle({
            oracleId: oracleId,
            metadataURI: metadataURI,
            active: false,
            exists: true
        });

        totalOracles += 1;

        emit OracleRegistered(msg.sender, oracleId, metadataURI);
    }

    /*//////////////////////////////////////////////////////////////
                        GOVERNANCE CONTROLS
    //////////////////////////////////////////////////////////////*/

    function activateOracle(address oracle) external onlyGovernance {
        Oracle storage o = oracles[oracle];
        if (!o.exists) revert OracleNotRegistered();
        o.active = true;
        emit OracleActivated(oracle);
    }

    function deactivateOracle(address oracle) external onlyGovernance {
        Oracle storage o = oracles[oracle];
        if (!o.exists) revert OracleNotRegistered();
        o.active = false;
        emit OracleDeactivated(oracle);
    }

    /*//////////////////////////////////////////////////////////////
                        VIEW FUNCTIONS
    //////////////////////////////////////////////////////////////*/

    function isActiveOracle(address oracle) external view returns (bool) {
        return oracles[oracle].active;
    }

    function getOracle(address oracle)
        external
        view
        returns (
            bytes32 oracleId,
            string memory metadataURI,
            bool active
        )
    {
        Oracle storage o = oracles[oracle];
        if (!o.exists) revert OracleNotRegistered();
        return (o.oracleId, o.metadataURI, o.active);
    }
}
","keccak256":"0x75e384f7eacae50b8cd424f619e190b718598665f62684a2ecf1a64bd0c0268c","license":"MIT"},"oracles/OracleStaking.sol":{"content":"// File: contracts/oracles/OracleStaking.sol
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/*
    OracleStaking.sol

    PURPOSE
    -------
    Handles staking, slashing, and withdrawal of oracle capital.
    This contract enforces:
    - minimum stake requirements
    - slashable capital for incorrect behavior
    - non-custodial withdrawals
    - governance-bounded slashing authority

    GUARANTEES (from docs)
    ---------------------
    - No oracle influence without stake
    - Slashing is deterministic and attributable
    - Funds are never custodied off-chain
    - Governance cannot arbitrarily seize funds

    TRUST MODEL
    -----------
    - Oracles are economically trusted
    - Governance is slow, bounded, auditable
*/

import {OracleRegistry} from "./OracleRegistry.sol";

contract OracleStaking {
    /*//////////////////////////////////////////////////////////////
                                ERRORS
    //////////////////////////////////////////////////////////////*/

    error OnlyGovernance();
    error OracleNotActive();
    error InvalidStakeAmount();
    error InsufficientStake();

    /*//////////////////////////////////////////////////////////////
                                EVENTS
    //////////////////////////////////////////////////////////////*/

    event StakeDeposited(address indexed oracle, uint256 amount);
    event StakeSlashed(address indexed oracle, uint256 amount);
    event StakeWithdrawn(address indexed oracle, uint256 amount);
    event MinimumStakeUpdated(uint256 newMinimumStake);

    /*//////////////////////////////////////////////////////////////
                              STORAGE
    //////////////////////////////////////////////////////////////*/

    /// @notice Governance authority
    address public governance;

    /// @notice Oracle registry
    OracleRegistry public immutable oracleRegistry;

    /// @notice Oracle address => stake
    mapping(address => uint256) public stakes;

    /// @notice Total oracle stake
    uint256 public totalStaked;

    /// @notice Minimum stake required to participate
    uint256 public minimumStake;

    /*//////////////////////////////////////////////////////////////
                              MODIFIERS
    //////////////////////////////////////////////////////////////*/

    modifier onlyGovernance() {
        if (msg.sender != governance) revert OnlyGovernance();
        _;
    }

    modifier onlyActiveOracle(address oracle) {
        if (!oracleRegistry.isActiveOracle(oracle)) revert OracleNotActive();
        _;
    }

    /*//////////////////////////////////////////////////////////////
                              CONSTRUCTOR
    //////////////////////////////////////////////////////////////*/

    constructor(
        address _governance,
        address _oracleRegistry,
        uint256 _minimumStake
    ) {
        require(_governance != address(0), "INVALID_GOVERNANCE");
        require(_oracleRegistry != address(0), "INVALID_REGISTRY");

        governance = _governance;
        oracleRegistry = OracleRegistry(_oracleRegistry);
        minimumStake = _minimumStake;
    }

    /*//////////////////////////////////////////////////////////////
                        GOVERNANCE CONTROLS
    //////////////////////////////////////////////////////////////*/

    function updateMinimumStake(uint256 newMinimumStake)
        external
        onlyGovernance
    {
        minimumStake = newMinimumStake;
        emit MinimumStakeUpdated(newMinimumStake);
    }

    /*//////////////////////////////////////////////////////////////
                        STAKING LOGIC
    //////////////////////////////////////////////////////////////*/

    function stake() external payable onlyActiveOracle(msg.sender) {
        if (msg.value == 0) revert InvalidStakeAmount();

        stakes[msg.sender] += msg.value;
        totalStaked += msg.value;

        emit StakeDeposited(msg.sender, msg.value);
    }

    /*//////////////////////////////////////////////////////////////
                        SLASHING LOGIC
    //////////////////////////////////////////////////////////////*/

    function slash(address oracle, uint256 amount)
        external
        onlyGovernance
    {
        uint256 current = stakes[oracle];
        if (amount == 0 || amount > current) revert InvalidStakeAmount();

        stakes[oracle] = current - amount;
        totalStaked -= amount;

        emit StakeSlashed(oracle, amount);
    }

    /*//////////////////////////////////////////////////////////////
                        WITHDRAWAL LOGIC
    //////////////////////////////////////////////////////////////*/

    function withdraw(uint256 amount) external {
        if (oracleRegistry.isActiveOracle(msg.sender)) revert OracleNotActive();

        uint256 current = stakes[msg.sender];
        if (amount == 0 || amount > current) revert InsufficientStake();

        stakes[msg.sender] = current - amount;
        totalStaked -= amount;

        (bool ok, ) = msg.sender.call{value: amount}("");
        require(ok, "TRANSFER_FAILED");

        emit StakeWithdrawn(msg.sender, amount);
    }

    /*//////////////////////////////////////////////////////////////
                        VIEW FUNCTIONS
    //////////////////////////////////////////////////////////////*/

    function getStake(address oracle) external view returns (uint256) {
        return stakes[oracle];
    }
}
